376: 	if hasMissingRefId {
377: 		// Find existing refIds
378: 		existingRefIds := make(map[string]bool)
379: 		for _, target := range targets {
380: 			if targetMap, ok := target.(map[string]interface{}); ok {
381: 				if refId, ok := targetMap["refId"].(string); ok {
382: 					existingRefIds[refId] = true
383: 				}
384: 			}
385: 		}
386: 
387: 		// Assign refIds to targets that don't have them
388: 		letters := "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
